diff --git a/llvm/include/llvm/Analysis/DependenceAnalysis.h b/llvm/include/llvm/Analysis/DependenceAnalysis.h
index d4167bba6f1ac..49e5b88d9a548 100644
--- a/llvm/include/llvm/Analysis/DependenceAnalysis.h
+++ b/llvm/include/llvm/Analysis/DependenceAnalysis.h
@@ -543,7 +543,7 @@ class DependenceInfo {
   bool testMIV(const SCEV *Src, const SCEV *Dst, const SmallBitVector &Loops,
                FullDependence &Result) const;

-  /// strongSIVtest - Tests the strong SIV subscript pair (Src and Dst)
+  /// strongSIVtest - Tests the strong SIV subscript pair (\p Src and \p Dst)
   /// for dependence.
   /// Things of the form [c1 + a*i] and [c2 + a*i],
   /// where i is an induction variable, c1 and c2 are loop invariant,
@@ -551,10 +551,9 @@ class DependenceInfo {
   /// Returns true if any possible dependence is disproved.
   /// If there might be a dependence, returns false.
   /// Sets appropriate direction and distance.
-  bool strongSIVtest(const SCEV *Coeff, const SCEV *SrcConst,
-                     const SCEV *DstConst, const Loop *CurrentSrcLoop,
-                     const Loop *CurrentDstLoop, unsigned Level,
-                     FullDependence &Result, bool UnderRuntimeAssumptions);
+  bool strongSIVtest(const SCEVAddRecExpr *Src, const SCEVAddRecExpr *Dst,
+                     unsigned Level, FullDependence &Result,
+                     bool UnderRuntimeAssumptions);

   /// weakCrossingSIVtest - Tests the weak-crossing SIV subscript pair
   /// (Src and Dst) for dependence.
diff --git a/llvm/lib/Analysis/DependenceAnalysis.cpp b/llvm/lib/Analysis/DependenceAnalysis.cpp
index ab8c8e578dfd2..f2d8abf7aeef4 100644
--- a/llvm/lib/Analysis/DependenceAnalysis.cpp
+++ b/llvm/lib/Analysis/DependenceAnalysis.cpp
@@ -1172,32 +1172,6 @@ static const SCEV *minusSCEVNoSignedOverflow(const SCEV *A, const SCEV *B,
   return nullptr;
 }

-/// Returns \p A * \p B if it guaranteed not to signed wrap. Otherwise returns
-/// nullptr. \p A and \p B must have the same integer type.
-static const SCEV *mulSCEVNoSignedOverflow(const SCEV *A, const SCEV *B,
-                                           ScalarEvolution &SE) {
-  if (SE.willNotOverflow(Instruction::Mul, /*Signed=*/true, A, B))
-    return SE.getMulExpr(A, B);
-  return nullptr;
-}
-
-/// Returns the absolute value of \p A. In the context of dependence analysis,
-/// we need an absolute value in a mathematical sense. If \p A is the signed
-/// minimum value, we cannot represent it unless extending the original type.
-/// Thus if we cannot prove that \p A is not the signed minimum value, returns
-/// nullptr.
-static const SCEV *absSCEVNoSignedOverflow(const SCEV *A, ScalarEvolution &SE) {
-  IntegerType *Ty = cast<IntegerType>(A->getType());
-  if (!Ty)
-    return nullptr;
-
-  const SCEV *SMin =
-      SE.getConstant(APInt::getSignedMinValue(Ty->getBitWidth()));
-  if (!SE.isKnownPredicate(CmpInst::ICMP_NE, A, SMin))
-    return nullptr;
-  return SE.getAbsExpr(A, /*IsNSW=*/true);
-}
-
 /// Returns true iff \p Test is enabled.
 static bool isDependenceTestEnabled(DependenceTestType Test) {
   if (EnableDependenceTest == DependenceTestType::All)
@@ -1261,14 +1235,18 @@ bool DependenceInfo::testZIV(const SCEV *Src, const SCEV *Dst,
 //                { > if d < 0
 //
 // Return true if dependence disproved.
-bool DependenceInfo::strongSIVtest(const SCEV *Coeff, const SCEV *SrcConst,
-                                   const SCEV *DstConst, const Loop *CurSrcLoop,
-                                   const Loop *CurDstLoop, unsigned Level,
+bool DependenceInfo::strongSIVtest(const SCEVAddRecExpr *Src,
+                                   const SCEVAddRecExpr *Dst, unsigned Level,
                                    FullDependence &Result,
                                    bool UnderRuntimeAssumptions) {
   if (!isDependenceTestEnabled(DependenceTestType::StrongSIV))
     return false;

+  const SCEV *Coeff = Src->getStepRecurrence(*SE);
+  assert(Coeff == Dst->getStepRecurrence(*SE) &&
+         "Expecting same coefficient in Strong SIV test");
+  const SCEV *SrcConst = Src->getStart();
+  const SCEV *DstConst = Dst->getStart();
   LLVM_DEBUG(dbgs() << "\tStrong SIV test\n");
   LLVM_DEBUG(dbgs() << "\t    Coeff = " << *Coeff);
   LLVM_DEBUG(dbgs() << ", " << *Coeff->getType() << "\n");
@@ -1280,6 +1258,15 @@ bool DependenceInfo::strongSIVtest(const SCEV *Coeff, const SCEV *SrcConst,
   assert(0 < Level && Level <= CommonLevels && "level out of range");
   Level--;

+  // First try to prove independence based on the ranges of the two subscripts.
+  ConstantRange SrcRange = SE->getSignedRange(Src);
+  ConstantRange DstRange = SE->getSignedRange(Dst);
+  if (SrcRange.intersectWith(DstRange).isEmptySet()) {
+    ++StrongSIVindependence;
+    ++StrongSIVsuccesses;
+    return true;
+  }
+
   const SCEV *Delta = minusSCEVNoSignedOverflow(SrcConst, DstConst, *SE);
   if (!Delta) {
     Result.Consistent = false;
@@ -1288,30 +1275,6 @@ bool DependenceInfo::strongSIVtest(const SCEV *Coeff, const SCEV *SrcConst,
   LLVM_DEBUG(dbgs() << "\t    Delta = " << *Delta);
   LLVM_DEBUG(dbgs() << ", " << *Delta->getType() << "\n");

-  // check that |Delta| < iteration count
-  bool IsDeltaLarge = [&] {
-    const SCEV *UpperBound = collectUpperBound(CurSrcLoop, Delta->getType());
-    if (!UpperBound)
-      return false;
-
-    LLVM_DEBUG(dbgs() << "\t    UpperBound = " << *UpperBound);
-    LLVM_DEBUG(dbgs() << ", " << *UpperBound->getType() << "\n");
-    const SCEV *AbsDelta = absSCEVNoSignedOverflow(Delta, *SE);
-    const SCEV *AbsCoeff = absSCEVNoSignedOverflow(Coeff, *SE);
-    if (!AbsDelta || !AbsCoeff)
-      return false;
-    const SCEV *Product = mulSCEVNoSignedOverflow(UpperBound, AbsCoeff, *SE);
-    if (!Product)
-      return false;
-    return SE->isKnownPredicate(CmpInst::ICMP_SGT, AbsDelta, Product);
-  }();
-  if (IsDeltaLarge) {
-    // Distance greater than trip count - no dependence
-    ++StrongSIVindependence;
-    ++StrongSIVsuccesses;
-    return true;
-  }
-
   // Can we compute distance?
   if (isa<SCEVConstant>(Delta) && isa<SCEVConstant>(Coeff)) {
     APInt ConstDelta = cast<SCEVConstant>(Delta)->getAPInt();
@@ -2357,9 +2320,8 @@ bool DependenceInfo::testSIV(const SCEV *Src, const SCEV *Dst, unsigned &Level,
     Level = mapSrcLoop(CurSrcLoop);
     bool disproven;
     if (SrcCoeff == DstCoeff)
-      disproven =
-          strongSIVtest(SrcCoeff, SrcConst, DstConst, CurSrcLoop, CurDstLoop,
-                        Level, Result, UnderRuntimeAssumptions);
+      disproven = strongSIVtest(SrcAddRec, DstAddRec, Level, Result,
+                                UnderRuntimeAssumptions);
     else if (SrcCoeff == SE->getNegativeSCEV(DstCoeff))
       disproven = weakCrossingSIVtest(SrcCoeff, SrcConst, DstConst, CurSrcLoop,
                                       CurDstLoop, Level, Result);

comments.body:
As I understand it, @amehsan's objection is: with this approach we would lose the ability to use the SCEV extension such as https://github.com/llvm/llvm-project/pull/91961, whereas their approach would preserve that ability. I really don't understand this objection, and I feel they are still misunderstanding something about SCEV.

- Perhaps they are conflating the "inference" of nowrap flags with the "transformation" of them.
- Probably they are also conflating the semantics of nowrap properties for **addrecs** with those for other SCEV expressions (e.g., add/mul). In the PRs that have been referred to, nobody has discussed about the nowrap properties of addrecs. I've asked several times to them for clarification on the semantics of context-sensitive nowrap flags for addrecs in this thread, but it still has not been answered. I suspect it may be impossible to explain that in the first place, because it may simply be ill-defined.

Furthermore, even if the above points are resolved, I think DA should **NOT** use the SCEV extensions. For example, if we have a loop like this:

```c
for (i = 0; i < N; i++) {
  if (cond0(i)) {
    A[i+c0] = ...;
  }

  if (cond1(i)) {
    A[i+c1] = ...;
  }
}
```

If we use the `SCEVUse` that is suggested in #91961, then we obtain an addrec `{c0,+,a}` which may be meaningful only under the condition `cond0(i)`, and another addrec `{c1,+,a}` which may be meaningful only under the condition `cond1(i)`. So, what does the arithmetic `c0 - c1` actually mean? I'm not entirely sure, but the result *may be meaningful only under the combined condition* `cond0(i) && cond1(i)`. If that's the case, it effectively implies that the dependence tests assume `cond0(i) && cond1(i)` globally. This is very problematic, as we can no longer distinguish the original program from the following one:

```c
for (i = 0; i < N; i++) {
  if (cond0(i) && cond1(i)) {
    A[i+c0] = ...;
    A[i+c1] = ...;
  }
}
```

If `cond0(i) && cond1(i)` is always false (e.g., `i % 2 == 0 && i % 2 == 1`), DA is allowed to yield arbitrary results, e.g., no-dependence between the two stores. It's clearly incorrect, because the following program has a dependence between the two stores:

```c
for (i = 0; i < N; i++) {
  if (i % 2 == 0) {
    A[i + 1] = ...;
  }

  if (i % 2 == 1) {
    A[i] = ...;
  }
}
```

I don't expect such a simple counter-example to exist, but using context-sensitive information in SCEV may make DA unsound, as DA analyzes loop-carried dependencies. In my understanding, the justification for using the SCEV framework in DA is the fact that the *context of the SCEV is global*. If we allow the context-sensitive analysis in SCEV, it could violate the fundamental assumption of DA.

> Furthermore, even if the above points are resolved, I think DA should **NOT** use the SCEV extensions. For example, if we have a loop like this:
> 
> ```c
> for (i = 0; i < N; i++) {
>   if (cond0(i)) {
>     A[i+c0] = ...;
>   }
> 
>   if (cond1(i)) {
>     A[i+c1] = ...;
>   }
> }
> ```
> 
> If we use the `SCEVUse` that is suggested in #91961, then we obtain an addrec `{c0,+,a}` which may be meaningful only under the condition `cond0(i)`, and another addrec `{c1,+,a}` which may be meaningful only under the condition `cond1(i)`. So, what does the arithmetic `c0 - c1` actually mean? I'm not entirely sure, but the result _may be meaningful only under the combined condition_ `cond0(i) && cond1(i)`

The cases that we care about `c0` and `c1` are loop invariant. So they are meaningful independent of the condition. If you have a concrete example please share it. But even if there is a `c1` that is meaningful only for some iterations of the loop and not the others, then that subscript will not qualify for StrongSIV (or probably any other DA test). SCEV can easily avoid assigning per-use nsw flags to such cases.

Can we express the condition proposed here like this instead?
```
ConstantRange SrcRange = SE->getSignedRange(Src);
ConstantRange DstRange = SE->getSignedRange(Dst);
return SrcRange.intersectWith(DstRange).isEmptySet();
```
This leaves the heavy lifting to SCEV and does not require nowrap flags -- not that I expect it to be useful, but we *can* prove disjointness of wrapping ranges as well. It's also not specific to *strong* SIV in particular. This seems like something we should just be checking upfront to discharge the "obvious" cases that BasicAA does not catch itself.

(Note that this does not take into account overlap due to the size of the final access -- but it looks like DA does isKnownMultipleOf checks early on to not have to deal with this.)
